starterCode.javascript:
// Create a memoized component
const MemoizedComponent = ({ state, props, deps }) => {
  // Render the component
  return <div>{state.a} {state.b}</div>
};

// Use the memoized component
function App() {
  const [state, setState] = useState({ a: 1, b: 2 });
  const [props, setProps] = useState({ c: 3, d: 4 });
  const deps = [state.a, state.b];
  return <MemoizedComponent state={state} props={props} deps={deps} />;
}

